+const express = require('express');
+const db = require('../database');
+const bcrypt = require('bcryptjs');
+const router = express.Router();
+const dateHelper = require('../utils/dateHelper');
+
+// ==================== إدارة المستخدمين (الكاشير) ====================
+
+// جلب جميع المستخدمين
+router.get('/users', (req, res) => {
+  db.all('SELECT id, name, email, username, phone, role, status, created_at FROM users ORDER BY created_at DESC', (err, rows) => {
+    if (err) return res.status(500).json({ error: err.message });
+    res.json(rows);
+  });
+});
+
+// جلب مستخدم محدد
+router.get('/users/:id', (req, res) => {
+  const { id } = req.params;
+  db.get(
+    `SELECT id, name, email, username, phone, role, status, created_at FROM users WHERE id = ?`,
+    [id],
+    (err, user) => {
+      if (err) return res.status(500).json({ error: err.message });
+      if (!user) return res.status(404).json({ error: 'User not found' });
+      res.json(user);
+    }
+  );
+});
+
+// إضافة كاشير جديد
+router.post('/users', (req, res) => {
+  const { name, email, username, password, phone, role = 'cashier', status = 'active' } = req.body;
+  const salt = bcrypt.genSaltSync(10);
+  const hash = bcrypt.hashSync(password, salt);
+  db.run(
+    `INSERT INTO users (name, email, username, password, phone, role, status) VALUES (?, ?, ?, ?, ?, ?, ?)`,
+    [name, email, username, hash, phone, role, status],
+    function(err) {
+      if (err) return res.status(500).json({ error: err.message });
+      res.json({ id: this.lastID, success: true });
+    }
+  );
+});
+
+// تعديل كاشير
+router.put('/users/:id', (req, res) => {
+  const { id } = req.params;
+  const { name, email, username, phone, role, status } = req.body;
+  db.run(
+    `UPDATE users SET name=?, email=?, username=?, phone=?, role=?, status=? WHERE id=?`,
+    [name, email, username, phone, role, status, id],
+    function(err) {
+      if (err) return res.status(500).json({ error: err.message });
+      res.json({ changes: this.changes, success: true });
+    }
+  );
+});
+
+// حذف كاشير
+router.delete('/users/:id', (req, res) => {
+  const { id } = req.params;
+  db.run('DELETE FROM users WHERE id = ?', [id], function(err) {
+    if (err) return res.status(500).json({ error: err.message });
+    res.json({ changes: this.changes, success: true });
+  });
+});
+
+// إعادة تعيين كلمة مرور كاشير
+router.post('/users/:id/reset-password', (req, res) => {
+  const { id } = req.params;
+  const { newPassword } = req.body;
+  const salt = bcrypt.genSaltSync(10);
