const express = require('express');
const db = require('../database');
const bcrypt = require('bcryptjs');
const router = express.Router();

// ==================== إدارة المستخدمين (الكاشير) ====================

// جلب جميع المستخدمين (الكاشير والمديرين)
router.get('/users', (req, res) => {
  db.all('SELECT id, name, email, username, phone, role, status, created_at FROM users ORDER BY created_at DESC', (err, rows) => {
    if (err) return res.status(500).json({ error: err.message });
    res.json(rows);
  });
});

// إضافة كاشير جديد
router.post('/users', (req, res) => {
  const { name, email, username, password, phone, role = 'cashier', status = 'active' } = req.body;
  const salt = bcrypt.genSaltSync(10);
  const hash = bcrypt.hashSync(password, salt);
  db.run(
    `INSERT INTO users (name, email, username, password, phone, role, status) VALUES (?, ?, ?, ?, ?, ?, ?)`,
    [name, email, username, hash, phone, role, status],
    function(err) {
      if (err) return res.status(500).json({ error: err.message });
      res.json({ id: this.lastID, success: true });
    }
  );
});

// تعديل كاشير
router.put('/users/:id', (req, res) => {
  const { id } = req.params;
  const { name, email, username, phone, role, status } = req.body;
  let query = `UPDATE users SET name=?, email=?, username=?, phone=?, role=?, status=? WHERE id=?`;
  let params = [name, email, username, phone, role, status, id];
  db.run(query, params, function(err) {
    if (err) return res.status(500).json({ error: err.message });
    res.json({ changes: this.changes, success: true });
  });
});

// حذف كاشير
router.delete('/users/:id', (req, res) => {
  const { id } = req.params;
  db.run('DELETE FROM users WHERE id = ?', [id], function(err) {
    if (err) return res.status(500).json({ error: err.message });
    res.json({ changes: this.changes, success: true });
  });
});

// إعادة تعيين كلمة مرور كاشير
router.post('/users/:id/reset-password', (req, res) => {
  const { id } = req.params;
  const { newPassword } = req.body;
  const salt = bcrypt.genSaltSync(10);
  const hash = bcrypt.hashSync(newPassword, salt);
  db.run('UPDATE users SET password = ? WHERE id = ?', [hash, id], function(err) {
    if (err) return res.status(500).json({ error: err.message });
    res.json({ success: true });
  });
});

// ==================== تقارير الأداء ====================

// إحصائيات عامة
router.get('/stats', (req, res) => {
  const today = new Date().toISOString().split('T')[0];
  const startOfWeek = new Date(); startOfWeek.setDate(startOfWeek.getDate() - startOfWeek.getDay()); startOfWeek.setHours(0,0,0,0);
  const startOfMonth = new Date(); startOfMonth.setDate(1); startOfMonth.setHours(0,0,0,0);
  
  const queries = {
    todaySales: `SELECT COALESCE(SUM(total), 0) as total FROM transactions WHERE DATE(created_at) = ?`,
    todayTransactions: `SELECT COUNT(*) as count FROM transactions WHERE DATE(created_at) = ?`,
    monthSales: `SELECT COALESCE(SUM(total), 0) as total FROM transactions WHERE created_at >= ?`,
    totalCashiers: `SELECT COUNT(*) as count FROM users WHERE role = 'cashier'`,
    topCashierToday: `
      SELECT cashier_id, cashier_name, COUNT(*) as transactions, SUM(total) as total
      FROM transactions
      WHERE DATE(created_at) = ?
      GROUP BY cashier_id
      ORDER BY total DESC
      LIMIT 1
    `,
    lowStock: `SELECT COUNT(*) as count FROM products WHERE stock <= min_stock`
  };

  db.serialize(() => {
    db.get(queries.todaySales, [today], (err, todaySales) => {
      db.get(queries.todayTransactions, [today], (err, todayTransactions) => {
        db.get(queries.monthSales, [startOfMonth.toISOString()], (err, monthSales) => {
          db.get(queries.totalCashiers, [], (err, totalCashiers) => {
            db.get(queries.topCashierToday, [today], (err, topCashier) => {
              db.get(queries.lowStock, [], (err, lowStock) => {
                res.json({
                  todaySales: todaySales?.total || 0,
                  todayTransactions: todayTransactions?.count || 0,
                  monthSales: monthSales?.total || 0,
                  totalCashiers: totalCashiers?.count || 0,
                  topCashier: topCashier || null,
                  lowStock: lowStock?.count || 0
                });
              });
            });
          });
        });
      });
    });
  });
});

// أداء الكاشير مع فلترة حسب التاريخ
router.get('/cashier-performance', (req, res) => {
  const { startDate, endDate, cashierId } = req.query;
  let query = `
    SELECT 
      u.id, u.name,
      COUNT(t.id) as transactions,
      COALESCE(SUM(t.total), 0) as total_sales,
      COALESCE(AVG(t.total), 0) as avg_order,
      MAX(t.created_at) as last_sale
    FROM users u
    LEFT JOIN transactions t ON u.id = t.cashier_id
  `;
  const conditions = [];
  const params = [];

  if (startDate && endDate) {
    conditions.push(`t.created_at BETWEEN ? AND ?`);
    params.push(startDate, endDate);
  } else if (startDate) {
    conditions.push(`t.created_at >= ?`);
    params.push(startDate);
  } else if (endDate) {
    conditions.push(`t.created_at <= ?`);
    params.push(endDate);
  }

  if (cashierId) {
    conditions.push(`u.id = ?`);
    params.push(cashierId);
  }

  if (conditions.length) {
    query += ' WHERE ' + conditions.join(' AND ');
  }

  query += ` GROUP BY u.id ORDER BY total_sales DESC`;

  db.all(query, params, (err, rows) => {
    if (err) return res.status(500).json({ error: err.message });
    res.json(rows);
  });
});

// تفاصيل مبيعات كاشير معين (للتقرير التفصيلي)
router.get('/cashier-sales/:cashierId', (req, res) => {
  const { cashierId } = req.params;
  const { startDate, endDate } = req.query;
  let query = `SELECT * FROM transactions WHERE cashier_id = ?`;
  const params = [cashierId];
  if (startDate && endDate) {
    query += ` AND created_at BETWEEN ? AND ?`;
    params.push(startDate, endDate);
  } else if (startDate) {
    query += ` AND created_at >= ?`;
    params.push(startDate);
  } else if (endDate) {
    query += ` AND created_at <= ?`;
    params.push(endDate);
  }
  query += ` ORDER BY created_at DESC`;

  db.all(query, params, (err, transactions) => {
    if (err) return res.status(500).json({ error: err.message });
    // جلب العناصر لكل معاملة (اختياري)
    let completed = 0;
    if (transactions.length === 0) return res.json([]);
    transactions.forEach(t => {
      db.all('SELECT * FROM transaction_items WHERE transaction_id = ?', [t.id], (err, items) => {
        t.items = items;
        completed++;
        if (completed === transactions.length) res.json(transactions);
      });
    });
  });
});

module.exports = router;
